scripts.content:
extends Node

signal interacted(target: Node)
signal focus_changed(target: Node)

@export var raycast_length: float = {{raycast_length}}

var _current_target: Node = null
var _prompt_label: Label = null

func _ready():
	_prompt_label = $InteractionPrompt

func _physics_process(_delta):
	var camera := get_viewport().get_camera_3d()
	if camera == null:
		return

	var space_state := camera.get_world_3d().direct_space_state
	var origin := camera.global_position
	var end := origin + -camera.global_transform.basis.z * raycast_length
	var query := PhysicsRayQueryParameters3D.create(origin, end)
	var result := space_state.intersect_ray(query)

	if result.is_empty():
		_clear_target()
		return

	var collider: Node = result.collider
	var target: Node = _find_interactable(collider)
	if target != _current_target:
		_clear_target()
		if target:
			_current_target = target
			focus_changed.emit(target)
			_show_prompt(target)

func _input(event):
	if event.is_action_pressed("interact") and _current_target:
		interacted.emit(_current_target)

func _find_interactable(node: Node) -> Node:
	var current := node
	while current:
		if current.is_in_group("interactable"):
			return current
		current = current.get_parent()
	return null

func _clear_target():
	if _current_target:
		focus_changed.emit(null)
	_current_target = null
	_hide_prompt()

func _show_prompt(target: Node) -> void:
	if _prompt_label and target.has_method("get_interaction_prompt"):
		_prompt_label.text = target.get_interaction_prompt()
		_prompt_label.visible = true

func _hide_prompt():
	if _prompt_label:
		_prompt_label.visible = false
